/* =========================================
   Weather Dashboard — Modern CSS Styles
   ========================================= */

/* Google Font */
@import url('https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700&display=swap');

/* ---- Reset & Base ---- */
*, *::before, *::after {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

body {
  font-family: 'Inter', sans-serif;
  min-height: 100vh;
  background: linear-gradient(135deg, #0f2027, #203a43, #2c5364);
  background-attachment: fixed;
  color: #e0f2fe;
  display: flex;
  justify-content: center;
  align-items: flex-start;
  padding: 40px 16px;
}

/* ---- Container ---- */
.container {
  width: 100%;
  max-width: 760px;
  display: flex;
  flex-direction: column;
  gap: 24px;
}

/* ---- Header ---- */
header {
  text-align: center;
}

header h1 {
  font-size: 2.2rem;
  font-weight: 700;
  letter-spacing: 1px;
  color: #ffffff;
  text-shadow: 0 2px 12px rgba(0, 180, 255, 0.4);
}

header .subtitle {
  margin-top: 6px;
  font-size: 0.95rem;
  color: #93c5fd;
  font-weight: 300;
}

/* ---- Search Section ---- */
.search-section {
  display: flex;
  flex-direction: column;
  gap: 12px;
}

.search-box {
  display: flex;
  gap: 10px;
  align-items: center;
}

.search-box input {
  flex: 1;
  padding: 14px 18px;
  border-radius: 12px;
  border: 1.5px solid rgba(255, 255, 255, 0.15);
  background: rgba(255, 255, 255, 0.08);
  color: #ffffff;
  font-size: 1rem;
  outline: none;
  backdrop-filter: blur(6px);
  transition: border-color 0.25s, background 0.25s;
}

.search-box input::placeholder {
  color: #94a3b8;
}

.search-box input:focus {
  border-color: #38bdf8;
  background: rgba(255, 255, 255, 0.13);
}

.search-box button {
  padding: 14px 22px;
  border: none;
  border-radius: 12px;
  font-size: 0.95rem;
  font-weight: 600;
  cursor: pointer;
  transition: transform 0.15s, background 0.2s;
}

#get-weather-btn {
  background: linear-gradient(135deg, #0ea5e9, #0284c7);
  color: #ffffff;
  white-space: nowrap;
}

#get-weather-btn:hover {
  background: linear-gradient(135deg, #38bdf8, #0ea5e9);
  transform: translateY(-1px);
}

#location-btn {
  background: rgba(255, 255, 255, 0.1);
  color: #ffffff;
  font-size: 1.3rem;
  padding: 12px 16px;
  border: 1.5px solid rgba(255, 255, 255, 0.15);
}

#location-btn:hover {
  background: rgba(255, 255, 255, 0.2);
  transform: translateY(-1px);
}

/* ---- Recent Searches ---- */
.recent-searches {
  display: flex;
  align-items: center;
  gap: 8px;
  flex-wrap: wrap;
}

.recent-label {
  font-size: 0.8rem;
  color: #94a3b8;
  font-weight: 500;
}

#recent-list {
  display: flex;
  gap: 8px;
  flex-wrap: wrap;
}

#recent-list button {
  padding: 5px 14px;
  border-radius: 20px;
  border: 1px solid rgba(255, 255, 255, 0.2);
  background: rgba(255, 255, 255, 0.07);
  color: #bae6fd;
  font-size: 0.82rem;
  cursor: pointer;
  transition: background 0.2s;
}

#recent-list button:hover {
  background: rgba(255, 255, 255, 0.15);
}

/* ---- Unit Toggle ---- */
.unit-toggle {
  display: flex;
  justify-content: flex-end;
}

#unit-btn {
  padding: 8px 20px;
  border-radius: 20px;
  border: 1.5px solid rgba(255, 255, 255, 0.2);
  background: rgba(255, 255, 255, 0.07);
  color: #bae6fd;
  font-size: 0.9rem;
  font-weight: 600;
  cursor: pointer;
  transition: background 0.2s;
}

#unit-btn:hover {
  background: rgba(255, 255, 255, 0.15);
}

/* ---- Spinner ---- */
.spinner {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 12px;
  padding: 30px 0;
  color: #93c5fd;
  font-size: 0.9rem;
}

.spin {
  width: 42px;
  height: 42px;
  border: 4px solid rgba(255, 255, 255, 0.1);
  border-top-color: #38bdf8;
  border-radius: 50%;
  animation: spin 0.8s linear infinite;
}

@keyframes spin {
  to { transform: rotate(360deg); }
}

/* ---- Error Banner ---- */
.error-banner {
  background: rgba(239, 68, 68, 0.2);
  border: 1px solid rgba(239, 68, 68, 0.5);
  color: #fca5a5;
  padding: 14px 18px;
  border-radius: 12px;
  font-size: 0.95rem;
  text-align: center;
  backdrop-filter: blur(6px);
}

/* ---- Current Weather Card ---- */
.weather-result {
  background: rgba(255, 255, 255, 0.07);
  border: 1px solid rgba(255, 255, 255, 0.12);
  border-radius: 20px;
  padding: 28px;
  backdrop-filter: blur(12px);
  box-shadow: 0 8px 32px rgba(0, 0, 0, 0.3);
}

.weather-header {
  display: flex;
  justify-content: space-between;
  align-items: flex-start;
  margin-bottom: 24px;
}

.weather-header h2 {
  font-size: 1.8rem;
  font-weight: 700;
  color: #ffffff;
}

#weather-date {
  margin-top: 4px;
  font-size: 0.88rem;
  color: #94a3b8;
}

#weather-icon {
  width: 72px;
  height: 72px;
  filter: drop-shadow(0 0 8px rgba(56, 189, 248, 0.5));
}

.weather-stats {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(130px, 1fr));
  gap: 16px;
}

.stat {
  background: rgba(255, 255, 255, 0.05);
  border: 1px solid rgba(255, 255, 255, 0.08);
  border-radius: 14px;
  padding: 16px;
  display: flex;
  flex-direction: column;
  gap: 6px;
  transition: background 0.2s;
}

.stat:hover {
  background: rgba(255, 255, 255, 0.1);
}

.stat-label {
  font-size: 0.75rem;
  text-transform: uppercase;
  letter-spacing: 0.8px;
  color: #64748b;
  font-weight: 500;
}

.stat-value {
  font-size: 1.25rem;
  font-weight: 600;
  color: #e0f2fe;
}

/* ---- 5-Day Forecast ---- */
.forecast-section {
  display: flex;
  flex-direction: column;
  gap: 16px;
}

.forecast-section h3 {
  font-size: 1rem;
  font-weight: 600;
  color: #93c5fd;
  text-transform: uppercase;
  letter-spacing: 1px;
}

.forecast-cards {
  display: grid;
  grid-template-columns: repeat(5, 1fr);
  gap: 12px;
}

.forecast-card {
  background: rgba(255, 255, 255, 0.06);
  border: 1px solid rgba(255, 255, 255, 0.1);
  border-radius: 16px;
  padding: 16px 10px;
  text-align: center;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 8px;
  backdrop-filter: blur(8px);
  transition: background 0.2s, transform 0.15s;
}

.forecast-card:hover {
  background: rgba(255, 255, 255, 0.12);
  transform: translateY(-3px);
}

.forecast-card .forecast-date {
  font-size: 0.78rem;
  color: #94a3b8;
  font-weight: 500;
}

.forecast-card img {
  width: 40px;
  height: 40px;
}

.forecast-card .forecast-high {
  font-size: 1rem;
  font-weight: 700;
  color: #ffffff;
}

.forecast-card .forecast-low {
  font-size: 0.85rem;
  color: #64748b;
}

.forecast-card .forecast-condition {
  font-size: 0.75rem;
  color: #93c5fd;
}

/* ---- Utility ---- */
.hidden {
  display: none !important;
}

/* ---- Responsive ---- */
@media (max-width: 600px) {
  header h1 {
    font-size: 1.6rem;
  }

  .search-box {
    flex-wrap: wrap;
  }

  .search-box input {
    width: 100%;
  }

  .forecast-cards {
    grid-template-columns: repeat(3, 1fr);
  }

  .weather-stats {
    grid-template-columns: repeat(2, 1fr);
  }
}

@media (max-width: 380px) {
  .forecast-cards {
    grid-template-columns: repeat(2, 1fr);
  }
}

