// api.js — handles all fetch calls to the Flask backend

const BASE_URL = 'http://127.0.0.1:5000';

async function fetchWeatherByCity(city) {
  const encodedCity = encodeURIComponent(city.trim());
  const response = await fetch(`${BASE_URL}/weather?city=${encodedCity}`);

  if (!response.ok) {
    const err = await response.json().catch(() => ({}));
    throw new Error(err.error || `Request failed (${response.status})`);
  }

  return response.json();
}

async function fetchWeatherByCoords(lat, lon) {
  const response = await fetch(`${BASE_URL}/weather?lat=${lat}&lon=${lon}`);

  if (!response.ok) {
    const err = await response.json().catch(() => ({}));
    throw new Error(err.error || `Request failed (${response.status})`);
  }

  return response.json();
}

// ui.js — all DOM read/write operations

let currentUnit = 'C';
let lastData = null;

function showSpinner() {
  document.getElementById('spinner').classList.remove('hidden');
  document.getElementById('error-banner').classList.add('hidden');
  document.getElementById('weather-result').classList.add('hidden');
  document.getElementById('forecast-section').classList.add('hidden');
}

function hideSpinner() {
  document.getElementById('spinner').classList.add('hidden');
}

function showError(message) {
  hideSpinner();
  const banner = document.getElementById('error-banner');
  banner.textContent = message;
  banner.classList.remove('hidden');
}

function hideError() {
  document.getElementById('error-banner').classList.add('hidden');
}

function convertTemp(celsius) {
  if (currentUnit === 'F') {
    return ((celsius * 9) / 5 + 32).toFixed(1) + ' °F';
  }
  return celsius.toFixed(1) + ' °C';
}

function renderWeather(data) {
  lastData = data;
  hideSpinner();
  hideError();

  // Current weather
  document.getElementById('city-name').textContent =
    `${data.city}, ${data.country}`;
  document.getElementById('weather-date').textContent =
    new Date().toLocaleDateString('en-GB', {
      weekday: 'long', year: 'numeric', month: 'long', day: 'numeric'
    });
  document.getElementById('temperature').textContent  = convertTemp(data.temperature);
  document.getElementById('feels-like').textContent   = convertTemp(data.feels_like);
