import requests
from flask import current_app


def get_weather_by_city(city: str) -> dict:
    return _fetch_weather(params={'q': city})


def get_weather_by_coords(lat: float, lon: float) -> dict:
    return _fetch_weather(params={'lat': lat, 'lon': lon})


def _fetch_weather(params: dict) -> dict:
    api_key = current_app.config['OWM_API_KEY']
    base_url = current_app.config['OWM_BASE_URL']

    if not api_key:
        raise ValueError('OPENWEATHER_API_KEY is not configured.')

    # ---- Current weather ----
    current_params = {**params, 'appid': api_key, 'units': 'metric'}
    current_resp = requests.get(
        f'{base_url}/weather',
        params=current_params,
        timeout=5
    )

    if current_resp.status_code == 404:
        raise LookupError('City not found.')
    current_resp.raise_for_status()
    current = current_resp.json()

    # ---- 5-day forecast ----
    forecast_resp = requests.get(
        f'{base_url}/forecast',
        params=current_params,
        timeout=5
    )
    forecast_resp.raise_for_status()
    forecast_raw = forecast_resp.json()

    return _parse(current, forecast_raw)


def _parse(current: dict, forecast_raw: dict) -> dict:
    # Build one entry per day (noon reading) from the 3-hour forecast list
    seen_dates = {}
    for item in forecast_raw.get('list', []):
        date = item['dt_txt'].split(' ')[0]
        time = item['dt_txt'].split(' ')[1]
        if date not in seen_dates and time == '12:00:00':
            seen_dates[date] = {
                'date':      date,
                'high':      round(item['main']['temp_max'], 1),
                'low':       round(item['main']['temp_min'], 1),
                'condition': item['weather'][0]['main'],
                'icon':      item['weather'][0]['icon'],
            }

    return {
        'city':        current['name'],
        'country':     current['sys']['country'],
        'temperature': round(current['main']['temp'], 1),
        'feels_like':  round(current['main']['feels_like'], 1),
        'humidity':    current['main']['humidity'],
        'wind_speed':  current['wind']['speed'],
        'condition':   current['weather'][0]['main'],
        'icon':        current['weather'][0]['icon'],
        'forecast':    list(seen_dates.values())[:5],
    }

